import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"macOS에 Java 설치","description":"macOS에 Java를 설치하는 방법에 대한 단계별 가이드.","frontmatter":{"title":"macOS에 Java 설치","description":"macOS에 Java를 설치하는 방법에 대한 단계별 가이드.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"ko_kr/players/installing-java/macos.md","filePath":"translated/ko_kr/players/installing-java/macos.md","lastUpdated":1772272927000}`);var c={name:`ko_kr/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">macOS에 Java 설치 <a class="header-anchor" href="#h1" aria-label="Permalink to “macOS에 Java 설치”">​</a></h1><p>이 가이드는 macOS에 Java 21을 설치하는 방법을 안내합니다.</p><p>Minecraft 런처에서 자체적인 Java 설치를 제공하기 때문에, 이 단락은 <code>.jar</code> 기반의 Fabric 설치기를 사용하고자 하거나, Minecraft 서버 <code>.jar</code>를 사용하고자 할 때에만 유용합니다.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 이미 Java가 설치되었는지 확인하기 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 이미 Java가 설치되었는지 확인하기”">​</a></h2><p>터미널(<code>/Applications/Utilities/Terminal.app</code>에 위치함) 아래 명령어를 입력하고 &lt;0&gt;엔터&lt;/0&gt; 를 누릅니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>다음과 같은 내용이 표시되어야 합니다.</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>버전 번호를 확인합니다: 이 예시에선 <code>21.0.9</code>라고 적혀있습니다.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Minecraft: Java Edition 1.21.11을 플레이 하려면, 적어도 Java 21 이상의 Java가 설치되어야 합니다.</p><p>만약 이 명령어가 Java 21보다 낮은 버전을 표시한다면, 기존의 Java 설치를 업데이트해야 합니다.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Java 21 다운로드하고 설치하기 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Java 21 다운로드하고 설치하기”">​</a></h2><p><a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium OpenJDK 21</a> 설치를 권장합니다:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Temurin Java 다운로드 홈페이지" loading="lazy"></p><p>&quot;21 - LTS&quot; 버전을 선택하고 <code>.PKG</code> 인스톨러 포맷을 고릅니다. 시스템 아키텍처에 맞는 빌드를 선택해야 합니다:</p><ul><li>Apple M 시리즈 칩이 탑재된 기기는, <code>aarch64</code> 선택</li><li>인텔 프로세서가 탑재된 기기는 <code>x64</code> 선택</li><li>Mac의 프로세서가 사용되었는지 알아내려면 <a href="https://support.apple.com/en-us/116943" target="_blank" rel="noreferrer">이 패이지를 참조하세요.</a></li></ul><p><code>.pkg</code> 파일 다운로드가 완료되었다면 파일을 열고 설치를 진행하세요:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Temurin Java Installer" loading="lazy"></p><p>설치를 진행하려면 관리자 비밀번호를 입럭합니다.</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="macOS 비밀번호 입력창" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Homebrew로 설치하기 <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Homebrew로 설치하기”">​</a></h3><p><a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>가 이미 설치되어 있다면 아래와 같이 명령어를 실행하여 설치할 수도 있습니다.</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Java 21이 올바르게 설치되었는지 확인하기 <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Java 21이 올바르게 설치되었는지 확인하기”">​</a></h2><p>설치가 완료되면 터미널 창을 다시 열고 명령어 <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code>을 실행하여 Java가 잘 설치되었는지 확인할 수 있습니다.</p><p>명령어가 성공적으로 실행되었다면, 아래와 같이 표시됩니다:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>문제가 발생했다면, 자유롭게 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric 디스코드(영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};